import React from "react";
import { NavLink, useLocation, useNavigate } from "react-router-dom";
import "./Sidebar.css";

const NAV_ITEMS = [
  { to: "/dashboard", label: "Home", match: "/dashboard", icon: <HomeIcon /> },
  { to: "/practice", label: "Practice", match: "/practice", icon: <PracticeIcon /> },
  { to: "/scenarios", label: "Scenarios", match: "/scenarios", icon: <ScenariosIcon /> },
  { to: "/progress", label: "Progress", match: "/progress", icon: <ProgressIcon /> },
  { divider: true },
  { to: "/settings", label: "Settings", match: "/settings", icon: <SettingsIcon /> },
];

export default function Sidebar({ onLogout }) {
  const location = useLocation();
  const navigate = useNavigate();

  return (
    <aside className="sidebar">
      {/* logo here */}

      <nav className="sidebar-nav">
        {NAV_ITEMS.map((item, index) => {
          if (item.divider) {
            return <div key={`divider-${index}`} className="sidebar-divider" />;
          }

          const isActive = location.pathname === item.match;

          return (
            <NavLink
              key={item.label}
              to={item.to}
              className={`sidebar-nav-item${isActive ? " active" : ""}`}
            >
              <span className="sidebar-nav-icon">{item.icon}</span>
              <span className="sidebar-nav-label">{item.label}</span>
            </NavLink>
          );
        })}

        <button
          type="button"
          className="sidebar-nav-item sidebar-logout-link"
          onClick={onLogout}
        >
          <span className="sidebar-nav-icon"><LogoutIcon /></span>
          <span className="sidebar-nav-label">Log out</span>
        </button>
      </nav>
    </aside>
  );
}
